import{_ as t,c as o,o as l,ae as i}from"./chunks/framework.CkyPvWOg.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"javascript/获取元素的尺寸和位置.md","filePath":"javascript/获取元素的尺寸和位置.md","lastUpdated":1773308029000}'),a={name:"javascript/获取元素的尺寸和位置.md"};function r(c,e,d,s,n,f){return l(),o("div",null,[...e[0]||(e[0]=[i('<h3 id="一-offsetparent" tabindex="-1">一. offsetParent <a class="header-anchor" href="#一-offsetparent" aria-label="Permalink to &quot;一. offsetParent&quot;">​</a></h3><ul><li><strong>作用</strong>: 获取距离该元素<strong>最近的已定位</strong>(position不为static)的祖先元素</li><li><strong>特殊情况</strong>‌：如果父级元素都没有定位，则返回<code>body</code>；如果元素<code>display</code>为<code>none</code>，则返回<code>null</code></li></ul><h3 id="二-offsetwidth与offsetheight" tabindex="-1">二. offsetWidth与offsetHeight <a class="header-anchor" href="#二-offsetwidth与offsetheight" aria-label="Permalink to &quot;二. offsetWidth与offsetHeight&quot;">​</a></h3><ul><li>计算方式： <code> offsetWidth</code> = <code>width</code>(样式设置) + 左右<code>padding</code> + 左右<code>border</code>;</li><li>特点: <strong>包含</strong>元素的‌内容宽度，内边距(<code>padding</code>),边框(<code>border</code>),<strong>不包含</strong>外边距(<code>margin</code>),<strong>滚动条</strong>；</li><li>返回值‌：纯数字，单位为像素，会四舍五入为整数</li></ul><h3 id="三-offsetleft与offsettop" tabindex="-1">三. offsetLeft与offsetTop <a class="header-anchor" href="#三-offsetleft与offsettop" aria-label="Permalink to &quot;三. offsetLeft与offsetTop&quot;">​</a></h3><ul><li>含义: <code>offsetLeft</code>返回元素左外边框至<code>offsetParent</code>左内边框的距离</li></ul><h3 id="四-‌clientwidth与clientheight" tabindex="-1">四. ‌clientWidth与clientHeight <a class="header-anchor" href="#四-‌clientwidth与clientheight" aria-label="Permalink to &quot;四. ‌clientWidth与clientHeight&quot;">​</a></h3><ul><li>‌计算方式‌: <code>clientWidth</code> = <code>width</code>(样式设置) + 左右<code>padding</code> - 垂直滚动条宽度</li><li>特点: <strong>仅包含</strong>元素的‌内容宽度‌和‌左右内边距（<code>padding</code>）, 不包含边框，减去滚动条宽度</li></ul><h3 id="五-‌clienttop与clientleft" tabindex="-1">五. ‌clientTop与clientLeft <a class="header-anchor" href="#五-‌clienttop与clientleft" aria-label="Permalink to &quot;五. ‌clientTop与clientLeft&quot;">​</a></h3><ul><li>通常对应元素的上边框和左边框宽度</li></ul><h3 id="六-‌scrollwidth与scrollheight" tabindex="-1">六. ‌scrollWidth与scrollHeight <a class="header-anchor" href="#六-‌scrollwidth与scrollheight" aria-label="Permalink to &quot;六. ‌scrollWidth与scrollHeight&quot;">​</a></h3><ul><li>含义‌：返回元素内容的实际宽度和高度，包括被滚动条隐藏的部分(<strong>即元素的实际尺寸，包括滚动条隐藏的部分</strong>)</li></ul><h3 id="七-‌scrolltop与scrollleft" tabindex="-1">七. ‌scrollTop与scrollLeft <a class="header-anchor" href="#七-‌scrolltop与scrollleft" aria-label="Permalink to &quot;七. ‌scrollTop与scrollLeft&quot;">​</a></h3><ul><li>作用‌：获取或设置元素内容垂直/水平滚动的像素数</li></ul>',14)])])}const g=t(a,[["render",r]]);export{p as __pageData,g as default};
